blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>szyk wyrazów w pytaniach i przeczeniach</strong>: użycie czasowników pomocniczych, budowę pytań z <em>wh-</em> i najczęstsze błędy.",
    "rules": [
        {
            "label": "Yes / No Questions",
            "color": "emerald",
            "text": "<strong>Do / Does / Did + Subject + Verb</strong> — podstawowy wzór pytania:",
            "example": "Do you like pizza?"
        },
        {
            "label": "Wh-Questions",
            "color": "blue",
            "text": "<strong>Wh-word + Auxiliary + Subject + Verb</strong> — pytania z where, what, why, how:",
            "example": "Where do you live?"
        },
        {
            "label": "Negatives",
            "color": "amber",
            "text": "<strong>Subject + Auxiliary + not + Verb</strong> — typowa budowa przeczenia:",
            "example": "I don't like apples."
        }
    ]
}

{
    "title": "1. Czasowniki pomocnicze",
    "intro": "Do budowy pytań i przeczeń bardzo często potrzebujesz tych form:",
    "items": [
        {
            "label": "Do",
            "title": "I / You / We / They",
            "subtitle": "Do you like coffee? / I do not know."
        },
        {
            "label": "Does",
            "title": "He / She / It",
            "subtitle": "Does she work? / He does not play."
        },
        {
            "label": "Did",
            "title": "Past Simple",
            "subtitle": "Did they come? / We did not see."
        }
    ]
}

{
    "title": "2. Yes / No questions",
    "sections": [
        {
            "label": "Ze zwykłymi czasownikami",
            "color": "emerald",
            "description": "Przy zwykłych czasownikach używamy <strong>do / does / did</strong> przed podmiotem.",
            "examples": [
                {
                    "en": "Do you like pizza?",
                    "ua": "Lubisz pizzę?"
                },
                {
                    "en": "Does she play tennis?",
                    "ua": "Czy ona gra w tenisa?"
                },
                {
                    "en": "Did they watch the show?",
                    "ua": "Czy oni oglądali ten program?"
                }
            ]
        },
        {
            "label": "Z to be i modalnymi",
            "color": "sky",
            "description": "Przy <strong>to be</strong> i czasownikach modalnych zwykle wystarczy zamienić miejscami podmiot i czasownik. Nie dodajemy wtedy do / does / did.",
            "examples": [
                {
                    "en": "Are you ready?",
                    "ua": "Czy jesteś gotowy?"
                },
                {
                    "en": "Is he coming?",
                    "ua": "Czy on nadchodzi?"
                },
                {
                    "en": "Can you swim?",
                    "ua": "Czy umiesz pływać?"
                },
                {
                    "en": "Have you finished?",
                    "ua": "Czy już skończyłeś?"
                }
            ]
        }
    ]
}

{
    "title": "3. Wh-questions",
    "sections": [
        {
            "label": "Budowa",
            "color": "emerald",
            "description": "Najczęstszy wzór to <strong>Wh-word + Auxiliary + Subject + Verb</strong>.",
            "examples": [
                {
                    "en": "Where do you live?",
                    "ua": "Gdzie mieszkasz?"
                },
                {
                    "en": "What did she eat?",
                    "ua": "Co ona jadła?"
                },
                {
                    "en": "Why are they running?",
                    "ua": "Dlaczego oni biegną?"
                },
                {
                    "en": "How can I help?",
                    "ua": "Jak mogę pomóc?"
                }
            ]
        },
        {
            "label": "Who / what jako podmiot",
            "color": "amber",
            "description": "Gdy <strong>who</strong> albo <strong>what</strong> samo jest podmiotem zdania, zwykle nie potrzebujesz dodatkowego czasownika pomocniczego.",
            "examples": [
                {
                    "en": "Who called you?",
                    "ua": "Kto do ciebie dzwonił?"
                },
                {
                    "en": "What happened?",
                    "ua": "Co się stało?"
                },
                {
                    "en": "Who lives here?",
                    "ua": "Kto tu mieszka?"
                }
            ],
            "note": "Porównaj: <em>Who called you?</em> i <em>Who did you call?</em>"
        }
    ]
}

{
    "title": "4. Przeczenia",
    "sections": [
        {
            "label": "Ze zwykłymi czasownikami",
            "color": "emerald",
            "description": "Przeczenie budujemy przez <strong>do / does / did + not</strong> przed czasownikiem głównym.",
            "examples": [
                {
                    "en": "I do not (don't) like apples.",
                    "ua": "Nie lubię jabłek."
                },
                {
                    "en": "She does not (doesn't) play football.",
                    "ua": "Ona nie gra w piłkę nożną."
                },
                {
                    "en": "They did not (didn't) see the movie.",
                    "ua": "Oni nie widzieli tego filmu."
                }
            ]
        },
        {
            "label": "Z to be i modalnymi",
            "color": "sky",
            "description": "Przy <strong>to be</strong> i czasownikach modalnych dodajemy <strong>not</strong> bezpośrednio po tej formie.",
            "examples": [
                {
                    "en": "He is not (isn't) ready.",
                    "ua": "On nie jest gotowy."
                },
                {
                    "en": "She was not (wasn't) there.",
                    "ua": "Jej tam nie było."
                },
                {
                    "en": "You must not (mustn't) touch it.",
                    "ua": "Nie wolno ci tego dotykać."
                },
                {
                    "en": "They cannot (can't) come.",
                    "ua": "Oni nie mogą przyjść."
                }
            ]
        }
    ]
}

{
    "title": "5. Formy skrócone",
    "intro": "W mowie i w nieformalnym piśmie często skracamy <em>not</em>:",
    "rows": [
        {
            "en": "do not",
            "ua": "don't",
            "note": "I don't know."
        },
        {
            "en": "does not",
            "ua": "doesn't",
            "note": "She doesn't like it."
        },
        {
            "en": "did not",
            "ua": "didn't",
            "note": "We didn't go."
        },
        {
            "en": "is not",
            "ua": "isn't",
            "note": "He isn't here."
        },
        {
            "en": "are not",
            "ua": "aren't",
            "note": "They aren't coming."
        },
        {
            "en": "will not",
            "ua": "won't",
            "note": "I won't forget."
        },
        {
            "en": "cannot",
            "ua": "can't",
            "note": "She can't swim."
        }
    ],
    "warning": "📌 W formalnym piśmie częściej używa się pełnych form."
}

{
    "title": "6. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak czasownika pomocniczego w pytaniu.",
            "wrong": "You like pizza?",
            "right": "✅ <span class=\"font-mono\">Do you like pizza?</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Brak czasownika pomocniczego w pytaniu z wh-.",
            "wrong": "Where you live?",
            "right": "✅ <span class=\"font-mono\">Where do you live?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zła forma po does.",
            "wrong": "She don't like it.",
            "right": "✅ <span class=\"font-mono\">She doesn't like it.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Przeczenie bez czasownika pomocniczego.",
            "wrong": "I no like apples.",
            "right": "✅ <span class=\"font-mono\">I don't like apples.</span>"
        }
    ]
}

{
    "title": "8. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawny wariant",
    "select_intro": "Wskaż zdanie z właściwym szykiem.",
    "selects": [
        {
            "label": "a) Do you like coffee? / b) You like coffee?",
            "prompt": "Który wariant jest poprawny?"
        },
        {
            "label": "a) Where does she live? / b) Where she lives?",
            "prompt": "Który wariant jest poprawny?"
        },
        {
            "label": "a) He don't work here. / b) He doesn't work here.",
            "prompt": "Który wariant jest poprawny?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Ułóż pytanie",
    "input_intro": "Zamień zdanie twierdzące w pytanie.",
    "inputs": [
        {
            "before": "You speak English.",
            "after": "→ Do you ...?"
        },
        {
            "before": "She works in a bank.",
            "after": "→ Does she ...?"
        },
        {
            "before": "They went to the party.",
            "after": "→ Did they ...?"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Ułóż przeczenie",
    "rephrase_intro": "Zamień zdanie twierdzące w przeczenie.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I like apples.",
            "example_target": "I don't like apples."
        },
        {
            "original": "1. She plays tennis.",
            "placeholder": "Napisz przeczenie"
        },
        {
            "original": "2. They watched the movie.",
            "placeholder": "Napisz przeczenie"
        }
    ]
}

{
    "title": "Strony w sekcji Word Order",
    "items": [
        {
            "label": "Basic Word Order — podstawowy szyk zdania",
            "current": false
        },
        {
            "label": "Word Order in Questions and Negatives — pytania i przeczenia",
            "current": true
        },
        {
            "label": "Word Order with Adverbs and Adverbials — przysłówki i okoliczniki",
            "current": false
        },
        {
            "label": "Word Order with Verbs and Objects — czasowniki i dopełnienia",
            "current": false
        },
        {
            "label": "Advanced Word Order / Emphasis — inwersja i akcent",
            "current": false
        }
    ]
}
